/// Событие от background-потока загрузки страницы в event loop.
///
/// Загрузка разбита на четыре фазы: (0) `EarlyPreloadHints` — хинты из первых
/// байт HTML для раннего старта subresource fetch-ов; (1) chunks сырых байт для
/// инкрементального парсинга и промежуточных кадров через
/// `IncrementalTreeBuilder::feed_bytes`; (2) `LoadDone` — все байты доступны,
/// запускаем полный pipeline (CSS + изображения); (3) `LoadError` — ошибка fetch.
enum LoadEvent {
    /// No-op wake-up (SDC-2). `winit`'s `ControlFlow::Wait` genuinely parks
    /// the event loop until an OS window event, a scheduled `WaitUntil`
    /// deadline, or a proxied user event arrives — an `AutomationCommand`
    /// enqueued from a BiDi/MCP thread is none of those, so without this the
    /// loop could sit parked indefinitely and never drain it.
    /// `AutomationHandle::execute` sends this through `load_proxy` right
    /// after queuing a command; `user_event` below does nothing with it —
    /// merely *receiving* a proxied event is what interrupts `Wait` and
    /// triggers the next `about_to_wait` (where automation commands are
    /// actually drained).
    AutomationWake,
    /// Subresource-хинты из первого chunk HTML (HTML LS §13.2.6.4.7
    /// «Speculative HTML parsing»). Отправляются ДО первого `HtmlChunk`,
    /// чтобы sink мог начать загружать CSS/шрифты ещё в процессе парсинга.
    /// Дедупликация с финальными хинтами из `LoadDone` — через
    /// `preload_dispatched` в `Lumen`.
    /// Последнее поле — generation навигации (U-1): идентификатор load-цикла,
    /// присвоенный в `reload`/`resumed`. `user_event` отбрасывает событие, если
    /// его generation не совпадает с `Lumen::load_generation` — защита от
    /// устаревших событий гонки навигаций (быстрый back/forward или клик по двум
    /// ссылкам подряд), которые иначе подмешали бы DOM/CSS прошлой страницы.
    EarlyPreloadHints(Vec<lumen_html_parser::PreloadHint>, ResourceBase, u64),
    /// Очередной chunk сырых байт HTML. UTF-8 границы не выравниваются —
    /// `IncrementalTreeBuilder::feed_bytes` буферизует незавершённые
    /// code-point-ы внутри. Последнее поле — generation навигации (U-1).
    HtmlChunk(Vec<u8>, u64),
    /// CSS загружен параллельным потоком для промежуточных streaming-кадров.
    /// Мёрджится в `Lumen::stream_sheet` и применяется в `paint_partial_dom`.
    /// Последнее поле — generation навигации (U-1).
    CssLoaded(Box<lumen_css_parser::Stylesheet>, u64),
    /// PH1-2c: картинка `<img>` декодирована параллельным потоком во время
    /// streaming. Регистрируется в renderer-е по ключу `src` и вызывает redraw —
    /// картинки появляются по мере прихода, а не разом в финальном `LoadDone`.
    /// Для анимированного GIF `animated` несёт все кадры (тикаются в
    /// `RedrawRequested`); `image` — нулевой кадр для немедленной отрисовки.
    ImageDecoded {
        src: String,
        image: Box<lumen_image::Image>,
        animated: Option<Box<lumen_image::AnimatedGif>>,
    },
    /// PH3-19: web-шрифт из @font-face url() декодирован в фоновом потоке.
    /// Регистрируется в FontRegistry + MultiFontMeasurer и вызывает relayout —
    /// текст появляется в fallback-шрифте сразу, подменяется по приходу (FOUT).
    FontLoaded {
        family: String,
        weight: u16,
        style: lumen_core::FontStyle,
        unicode_range: Vec<lumen_font::UnicodeRange>,
        bytes: Vec<u8>,
    },
    /// Все байты получены — для финального полного pipeline.
    /// Последнее поле — generation навигации (U-1).
    LoadDone(RawPage, u64),
    /// Ошибка при загрузке страницы. Последнее поле — generation навигации (U-1).
    LoadError(String, u64),
    /// BUG-171 этап 2: финальный pipeline (parse → JS → fetch подресурсов →
    /// layout) выполнен на фоновом потоке; готовый результат применяется на
    /// UI-потоке (`apply_loaded_page`) без блокировки event loop. Последнее
    /// поле — generation навигации (U-1).
    RenderDone(Box<RenderOutcome>, u64),
}

/// Готовый результат финального pipeline: display-list-страница, источник для
/// relayout и живой JS-хэндл (если включён QuickJS). Тип-алиас, чтобы вынести
/// сложную тройку из сигнатур (`render_bytes`, `RenderOutcome`).
type RenderedPage = (LoadedPage, LayoutSource, Option<Arc<dyn PersistentJs>>);

/// BUG-171 этап 2: результат финального off-UI-thread рендера (`render_bytes`),
/// пересылаемый назад на UI-поток через `LoadEvent::RenderDone`.
///
/// Все поля `Send`: `LoadedPage`/`LayoutSource` — обычные данные; `js_ctx` —
/// хэндл QuickJS (`Send + Sync` по ADR-014, создан на рендер-потоке);
/// `preload_dispatched` временно забран из `Lumen` на время рендера (он его
/// дедуплицирует) и возвращается для восстановления.
struct RenderOutcome {
    /// Готовая страница + источник layout + живой JS-хэндл; либо текст ошибки
    /// (`Box<dyn Error>` не `Send`, поэтому конвертируется в `String`).
    result: Result<RenderedPage, String>,
    /// Набор уже разосланных preload-хинтов, забранный из
    /// `Lumen::preload_dispatched` на время рендера.
    preload_dispatched: std::collections::HashSet<String>,
}

/// PH3-19: дескриптор @font-face url()-источника, ещё не загруженного в память.
/// Хранится в `ParsedPage` / `LoadedPage`; `apply_loaded_page` спавнит
/// фоновый поток fetch+decode для каждого, результат — `LoadEvent::FontLoaded`.
struct PendingWebFont {
    /// CSS `font-family` дескриптор.
    family: String,
    /// Разрешённый font-weight (400 = normal, 700 = bold).
    weight: u16,
    /// Разрешённый font-style.
    style: lumen_core::FontStyle,
    /// Сырая строка `unicode-range` дескриптора (None → покрывает все кодпоинты).
    unicode_range_str: Option<String>,
    /// URL для fetch (@font-face `src: url(...)`).
    url: String,
}

/// PH3-19: web-шрифт, уже загруженный и декодированный после `FontLoaded`.
/// Список хранится в `Lumen::web_fonts` и используется для пересборки
/// `MultiFontMeasurer` при каждом relayout — иначе resize/scroll-reflow
/// теряет web-метрики и откатывается к Inter.
// weight/style хранятся для будущего CSS font-matching (по weight/style дескрипторам @font-face).
// Clone: ADR-016 M2.2 — off-thread relayout захватывает владеющий снимок web-шрифтов.
#[derive(Clone)]
#[allow(dead_code)]
struct LoadedWebFont {
    /// CSS `font-family` дескриптор.
    family: String,
    /// Разрешённый font-weight.
    weight: u16,
    /// Разрешённый font-style.
    style: lumen_core::FontStyle,
    /// Диапазоны Unicode из @font-face `unicode-range` дескриптора.
    unicode_range: Vec<lumen_font::UnicodeRange>,
    /// Декодированные sfnt-байты (TrueType / OTF после WOFF/WOFF2-распаковки).
    bytes: Vec<u8>,
}

/// Размер одного HTML-chunk при разбивке для инкрементального парсинга.
const STREAM_CHUNK_BYTES: usize = 8 * 1024;
/// Минимальный интервал между промежуточными кадрами при streaming (мс) — ~60 Гц.
const STREAM_PAINT_INTERVAL_MS: u128 = 16;
/// Minimum interval between rAF batches (ms) — vsync gate at 60 Hz.
///
/// Prevents `requestAnimationFrame` from firing more than once per display frame
/// when `RedrawRequested` is delivered at higher frequency (e.g. from scroll events).
const RAF_MIN_INTERVAL_MS: f64 = 1000.0 / 60.0;

/// EventSink, который печатает сетевые события в stdout — это и есть
/// «network log» Phase 0, реализующий принцип №4 «каждый исходящий байт
/// виден». Позже заменится на структурированный UI-логгер.
struct StdoutEventSink;

impl EventSink for StdoutEventSink {
    fn emit(&self, event: &Event) {
        // Сетевой лог идёт в stderr, чтобы stdout dump-режимов оставался чистым
        // (на нём — только сериализованный результат pipeline-а). В оконном
        // режиме разница невидима: оба потока попадают в терминал.
        match event {
            Event::RequestStarted { url, .. } => eprintln!("→ GET {url}"),
            Event::RequestCompleted { url, status, .. } => eprintln!("← {status} {url}"),
            Event::RequestBlocked { url, reason, .. } => eprintln!("✗ {url} ({reason})"),
            Event::RequestFailed { url, stage, reason, .. } => {
                eprintln!("✗ {url} ({}: {reason})", stage.as_str());
            }
            Event::SubresourceHintFound { url, kind, priority } => {
                let label = match kind {
                    SubresourceKind::Stylesheet => "css",
                    SubresourceKind::Script => "js",
                    SubresourceKind::Image => "img",
                    SubresourceKind::Font => "font",
                    SubresourceKind::Preconnect { dns_only: true } => "dns-prefetch",
                    SubresourceKind::Preconnect { dns_only: false } => "preconnect",
                    SubresourceKind::Other { .. } => "preload",
                };
                let prio = match priority {
                    FetchPriority::High => "high",
                    FetchPriority::Medium => "medium",
                    FetchPriority::Low => "low",
                };
                eprintln!("⤷ preload {label} [{prio}] {url}");
            }
            Event::FormSubmit { method, action, body, .. } => {
                if body.is_empty() {
                    eprintln!("⊢ form {method} {action}");
                } else {
                    eprintln!("⊢ form {method} {action} body={body}");
                }
            }
            _ => {}
        }
    }
}

